(function(){"use strict";const THEME_KEY="theme-preference";function getStoredTheme(){return localStorage.getItem(THEME_KEY)}function getSystemTheme(){return window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light"}function applyTheme(theme){document.documentElement.setAttribute("data-theme",theme);const toggles=document.querySelectorAll(".theme-toggle");toggles.forEach(function(toggle){toggle.classList.toggle("dark",theme==="dark");toggle.setAttribute("aria-pressed",theme==="dark")})}function toggleTheme(){const current=document.documentElement.getAttribute("data-theme")||getSystemTheme();const next=current==="dark"?"light":"dark";localStorage.setItem(THEME_KEY,next);applyTheme(next)}function init(){const stored=getStoredTheme();if(stored){applyTheme(stored)}const toggles=document.querySelectorAll(".theme-toggle");toggles.forEach(function(toggle){toggle.addEventListener("click",toggleTheme)});const header=document.querySelector(".site-header");const floatingToggle=document.querySelector(".theme-toggle-floating");if(header&&floatingToggle){var observer=new IntersectionObserver(function(entries){entries.forEach(function(entry){floatingToggle.classList.toggle("visible",!entry.isIntersecting)})},{threshold:0});observer.observe(header)}window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",function(e){if(!getStoredTheme()){applyTheme(e.matches?"dark":"light")}})}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init)}else{init()}})();
